agent_as_tool.pattern:
@tool
def research(query: str) -> str:
    return str(Agent(system_prompt='specialist', tools=[...])(query).message)

workaround_human_input_tool.pattern:
@tool
def request_human_approval(summary: str) -> str:
    """Ask a human to approve an action; returns the decision."""
    return get_human_decision(summary)
